    public List&lt;Permission&gt; getPermissionByUsername(String username) &#123;
        User user = super.getOne(Wrappers.&lt;User&gt;lambdaQuery().eq(User::getUsername, username), true);
        return this.getPermissionByUser(user);
    &#125;

